import{_ as r,r as i,o as a,c as n,a as e,d as s,w as c,b as d,e as o}from"./app.c51d4dcb.js";const l={},h=d('<h1 id="request-lifecycle" tabindex="-1"><a class="header-anchor" href="#request-lifecycle" aria-hidden="true">#</a> Request Lifecycle</h1><h2 id="introduction" tabindex="-1"><a class="header-anchor" href="#introduction" aria-hidden="true">#</a> Introduction</h2><p>When using any tool in the &quot;real world&quot;, you feel more confident if you understand how that tool works. Application development is no different. When you understand how your development tools function, you feel more comfortable and confident using them.</p><p>The goal of this document is to give you a good, high-level overview of how the Confetti framework works. By getting to know the overall framework better, everything feels less &quot;magical&quot; and you will be more confident building your applications. If you don&#39;t understand all of the terms right away, don&#39;t lose heart! Just try to get a basic grasp of what is going on, and your knowledge will grow as you explore other sections of the documentation.</p><h2 id="lifecycle-overview" tabindex="-1"><a class="header-anchor" href="#lifecycle-overview" aria-hidden="true">#</a> Lifecycle Overview</h2><h3 id="service-providers" tabindex="-1"><a class="header-anchor" href="#service-providers" aria-hidden="true">#</a> Service Providers</h3><p>One of the most important bootstrapping actions is loading the <a href="providers">service providers</a> for your application. All of the service providers for the application are configured in the <code>app/providers/provider_index.go</code> file. First, the <code>Register</code> method will be called on all RegisterProviders. Then, once all providers have been registered, the <code>Boot</code> method will be called on the BootProviders.</p><p>Service providers are responsible for bootstrapping all the framework&#39;s various components, such as the database, configuration, queue, validation, and routing components. Since they bootstrap and configure every feature offered by the framework, service providers are the most important aspect of the entire Confetti bootstrap process. Feel free to create a service provider yourself.</p><blockquote><p>Service providers are loaded once (so before requests takes place). And can therefore lead to a performance profit. For example, you can have a cache warmup in a &#39;service provider&#39;.</p></blockquote><h3 id="incoming-request" tabindex="-1"><a class="header-anchor" href="#incoming-request" aria-hidden="true">#</a> Incoming Request</h3><p>The entry point for all requests to a Confetti application is the <code>main.go</code> file. This file listens to all incoming requests. The <code>main.go</code> file retrieves an instance of the Confetti application from <code>bootstrap/app.go</code> script. The first action taken by Confetti itself is to create an instance of the application / <a href="container">service container</a>.</p><h3 id="http-console-kernels" tabindex="-1"><a class="header-anchor" href="#http-console-kernels" aria-hidden="true">#</a> HTTP / Console Kernels</h3>',12),p=o("Next, the incoming request is sent to either the HTTP kernel or the console kernel, depending on the type of request that is entering the application. The "),u=e("code",null,"inter.Request",-1),f=o(" will be handed off to the router for dispatching. The router will run any route specific "),v=o("middleware"),g=o(" and dispatch the request to a controller."),m=e("h2",{id:"focus-on-service-providers",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#focus-on-service-providers","aria-hidden":"true"},"#"),o(" Focus On Service Providers")],-1),y=e("p",null,"Service providers are truly the key to bootstrapping a Confetti application. The application instance is created once and the service providers are bootstrapped once. Then when a request comes in, it is handed through global middlewares and route middlewares. It's really that simple!",-1),b=e("p",null,[o("Having a firm grasp of how a Confetti application is built and bootstrapped via service providers is very valuable. Your application's default service providers are stored in the "),e("code",null,"app/providers"),o(" directory.")],-1),w=e("p",null,[o("By default, "),e("code",null,"app/providers/app_service_provider.go"),o(" is fairly empty. This provider is a great place to add your application's own bootstrapping and service container bindings. For large applications, you may wish to create several service providers, each with a more granular type of bootstrapping.")],-1);function _(k,q){const t=i("RouterLink");return a(),n("div",null,[h,e("p",null,[p,u,f,s(t,{to:"/the-basics/middleware.html#assigning-middleware-to-routes"},{default:c(()=>[v]),_:1}),g]),m,y,b,w])}const T=r(l,[["render",_],["__file","lifecycle.html.vue"]]);export{T as default};
